class Solution {
public:
    string crackSafe(int n, int k) {
        string res = "";
        string path = "";
        for (int i = 0; i < n - 1; i++) {
            path += '0';
        }
        for (int i = 0; i < k; i++) {
            res += path;
        }
        for (int i = 0; i < k; i++) {
            res += (char)(i + '0');
        }
        return res;
    }
};
